insert into public.avatar_controller_profiles(controller_key,title,input_scheme,move_speed,sprint_speed,jump_force,camera_mode,camera_config,touch_config,keyboard_config,gamepad_config,animation_state_map,metadata,is_active)
values('rich-free-roam','Rich Free Roam','hybrid',4.8,8.2,6.8,'third-person','{"distance":4.8,"height":1.7,"fov":58}'::jsonb,'{"leftStick":true,"rightStick":true,"jumpButton":true,"actionButton":true}'::jsonb,'{"forward":"KeyW","back":"KeyS","left":"KeyA","right":"KeyD","jump":"Space","sprint":"ShiftLeft"}'::jsonb,'{"move":"left-stick","camera":"right-stick","jump":"south","action":"west"}'::jsonb,'{"idle":"boss-idle","walk":"boss-walk","run":"street-run","jump":"power-jump","action":"smoke-burst"}'::jsonb,'{"brand":"Rich Bizness","version":"1.0"}'::jsonb,true)
on conflict (controller_key) do update set title=excluded.title,input_scheme=excluded.input_scheme,move_speed=excluded.move_speed,sprint_speed=excluded.sprint_speed,jump_force=excluded.jump_force,camera_mode=excluded.camera_mode,camera_config=excluded.camera_config,touch_config=excluded.touch_config,keyboard_config=excluded.keyboard_config,gamepad_config=excluded.gamepad_config,animation_state_map=excluded.animation_state_map,metadata=excluded.metadata,is_active=true,updated_at=now();
create or replace function public.rb_save_avatar_studio(p_display_name text,p_preset_key text,p_aura text,p_outfit jsonb default '{}'::jsonb,p_accessories jsonb default '{}'::jsonb,p_smoke jsonb default '{}'::jsonb,p_emotes jsonb default '{}'::jsonb,p_character_type text default 'custom') returns jsonb language plpgsql security definer set search_path=public as $$ declare v_user uuid:=auth.uid();v_controller uuid;v_loadout uuid;v_avatar uuid; begin if v_user is null then raise exception 'Authentication required'; end if; select id into v_controller from public.avatar_controller_profiles where controller_key='rich-free-roam' and is_active limit 1; insert into public.user_avatar_loadouts(user_id,controller_profile_id,display_name,outfit_config,accessory_config,aura_config,smoke_config,emote_config,animation_overrides,is_active,metadata) values(v_user,v_controller,nullif(trim(p_display_name),''),coalesce(p_outfit,'{}'::jsonb),coalesce(p_accessories,'{}'::jsonb),jsonb_build_object('name',coalesce(nullif(trim(p_aura),''),'Emerald Gold')),coalesce(p_smoke,'{}'::jsonb),coalesce(p_emotes,'{}'::jsonb),jsonb_build_object('preset',coalesce(nullif(trim(p_preset_key),''),'boss')),true,jsonb_build_object('source','avatar-studio','saved_at',now())) returning id into v_loadout; update public.user_avatar_loadouts set is_active=false,updated_at=now() where user_id=v_user and id<>v_loadout and is_active=true; insert into public.meta_avatars(user_id,display_name,aura,rank,level,xp,is_active,metadata,controller_profile_id,active_loadout_id,animation_state,movement_settings,character_type,is_realistic_3d,is_controllable) values(v_user,nullif(trim(p_display_name),''),coalesce(nullif(trim(p_aura),''),'Emerald Gold'),'Traveler',1,0,true,jsonb_build_object('preset_key',coalesce(nullif(trim(p_preset_key),''),'boss'),'outfit',coalesce(p_outfit,'{}'::jsonb),'accessories',coalesce(p_accessories,'{}'::jsonb),'smoke',coalesce(p_smoke,'{}'::jsonb),'emotes',coalesce(p_emotes,'{}'::jsonb)),v_controller,v_loadout,jsonb_build_object('state','idle','clip','boss-idle'),jsonb_build_object('controller','rich-free-roam','move_speed',4.8,'sprint_speed',8.2,'jump_force',6.8),coalesce(nullif(trim(p_character_type),''),'custom'),true,true) on conflict(user_id) do update set display_name=excluded.display_name,aura=excluded.aura,is_active=true,metadata=excluded.metadata,controller_profile_id=excluded.controller_profile_id,active_loadout_id=excluded.active_loadout_id,animation_state=excluded.animation_state,movement_settings=excluded.movement_settings,character_type=excluded.character_type,is_realistic_3d=true,is_controllable=true,updated_at=now() returning id into v_avatar; update public.profiles set preferred_avatar_loadout_id=v_loadout,has_avatar=true,updated_at=now() where id=v_user; return jsonb_build_object('avatar_id',v_avatar,'loadout_id',v_loadout,'controller_profile_id',v_controller,'saved',true); end $$;
revoke all on function public.rb_save_avatar_studio(text,text,text,jsonb,jsonb,jsonb,jsonb,text) from public,anon; grant execute on function public.rb_save_avatar_studio(text,text,text,jsonb,jsonb,jsonb,jsonb,text) to authenticated;
create index if not exists user_avatar_loadouts_user_active_idx on public.user_avatar_loadouts(user_id,is_active,updated_at desc); create index if not exists meta_avatars_controller_idx on public.meta_avatars(controller_profile_id) where is_active=true;